#include <stdio.h>
#include <stdlib.h>
#define MAXN 100005
int n, m, u, v, x, y, ans;
int a[MAXN], b[MAXN], c[MAXN];
void dfs(int x, int fa) {
    a[x] = b[x];
    for (int i = 0; i < n; i++) {
        if (c[i] == x) {
            dfs(i, x);
            a[x] ^= a[i];
        }
    }
}
int main() {
    scanf("%d", &n);
    for (int i = 0; i < n - 1; i++) {
        scanf("%d %d", &x, &y);
        c[x - 1] = y - 1;
        c[y - 1] = x - 1;
    }
    scanf("%d", &m);
    for (int i = 0; i < m; i++) {
        scanf("%d %d", &x, &y);
        dfs(x - 1, -1);
        dfs(y - 1, -1);
        ans = a[x - 1] ^ a[y - 1];
        printf("%d\n", ans);
    }
    return 0;
}

