#include <iostream>
#include <vector>
using namespace std;
const int MAXN = 100005;
int n, m, u, v, x, y, ans;
vector<int> a[MAXN], b[MAXN];
void dfs(int x, int fa) {
    for (int i = 0; i < a[x].size(); i++) {
        if (a[x][i] != fa) {
            dfs(a[x][i], x);
            b[x].push_back(b[a[x][i]]);
        }
    }
}
int main() {
    cin >> n;
    for (int i = 0; i < n - 1; i++) {
        cin >> x >> y;
        a[x - 1].push_back(y - 1);
        a[y - 1].push_back(x - 1);
    }
    cin >> m;
    for (int i = 0; i < m; i++) {
        cin >> x >> y;
        dfs(x - 1, -1);
        dfs(y - 1, -1);
        ans = b[x - 1].back() ^ b[y - 1].back();
        cout << ans << endl;
    }
    return 0;
}

