import java.util.ArrayList;
import java.util.Scanner;
public class Main {
    static final int MAXN = 100005;
    static int n, m, u, v, x, y, ans;
    static ArrayList<Integer>[] a = new ArrayList[MAXN];
    static ArrayList<Integer>[] b = new ArrayList[MAXN];
    public static void dfs(int x, int fa) {
        for (int i = 0; i < a[x].size(); i++) {
            if (a[x].get(i) != fa) {
                dfs(a[x].get(i), x);
                b[x].add(b[a[x].get(i)].get(b[a[x].get(i)].size() - 1));
            }
        }
    }
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        n = scanner.nextInt();
        for (int i = 0; i < n - 1; i++) {
            x = scanner.nextInt();
            y = scanner.nextInt();
            a[x - 1].add(y - 1);
            a[y - 1].add(x - 1);
        }
        m = scanner.nextInt();
        for (int i = 0; i < m; i++) {
            x = scanner.nextInt();
            y = scanner.nextInt();
            dfs(x - 1, -1);
            dfs(y - 1, -1);
            ans = b[x - 1].get(b[x - 1].size() - 1) ^ b[y - 1].get(b[y - 1].size() - 1);
            System.out.println(ans);
        }
    }
}

